\begin{flalign*}
\tan{\delta_x}=\tan{\frac{c}{c_x}}=\frac{\gamma_c}{\gamma_v} &=\sqrt{\frac{1-\frac{v_x^2}{c^2}}{1-\frac{c_x^2}{c^2}}}
