\sec{\alpha_x}=\delta_x &=\gamma_v &\cos{\alpha_x}=\frac{1}{\alpha_x}&=\frac{1}{\gamma_c}&&\\
\sec{\delta_x}=\alpha_x &=\gamma_c &\cos{\delta_x}=\frac{1}{\delta_x}&=\frac{1}{\gamma_v}&&\\
