\cot{\delta_x}=\frac{\delta_x}{\alpha_x} &=\frac{\gamma_v}{\gamma_c} &\tan{\delta_x}=\frac{\alpha_x}{\delta_x}&=\frac{\gamma_c}{\gamma_v}&&
\end{flalign*}

