&\therefore \quad \alpha_i = \frac{1}{\beta_v} = \frac{c}{v_i}\quad\&\quad\delta_i = \frac{1}{\beta_c} = \frac{c}{c_i} \quad \implies \quad c_i^2 + v_i^2 =c^2\quad\&\quad \gamma_v^2 + \gamma_c^2 = \gamma_v^2\gamma_c^2&&
\end{flalign*}

